var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>3년전, 북방합의체의 어느 연구소</color>","JPN":"<color=#ffd34c>3年前、北方合意体のとある研究所</color>","ENG":"<color=#ffd34c>3 years ago, One research lab in the Northern Union</color>","TWN":"<color=#ffd34c>3年前， 北方和議會某研究所</color>","SCN":"<color=#ffd34c>3年前， 北方联盟某研究所</color>","DEU":"<color=#ffd34c>3 years ago, One research lab in the Northern Union</color>","FRA":"<color=#ffd34c>3 years ago, One research lab in the Northern Union</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"이번에 입대한 아이, 서류 좀 볼까?","JPN":"今度入隊した子、書類を見れるか？","ENG":"Can I see the application form for the child that just enlisted?","TWN":"有關這次入伍的孩子，把資料給我看看？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"네. 박사님.","JPN":"はい、博士。","ENG":"Yes. Doctor.","TWN":"是，博士。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"음… 이름은 ■■. 고아원 출신….","JPN":"ふむ……名前は■■。孤児院出身……","ENG":"Mm... Her name is ■■, and an orphan...","TWN":"嗯……名字是■■，孤兒院出身……"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"입대 동기가 조금 특이해요. 세계평화, 정의 이런 게 적혀있던데요.","JPN":"入隊の志望理由が少し変わっています。世界平和とか正義だとか書かれてましたけど。","ENG":"Her reason for enlisting is a bit peculiar. It's written as \\"world peace and justice.\\"","TWN":"入伍動機有點特別。寫著世界和平、正義之類的。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"이번 아이는 얼마나 버틸 것 같으세요?","JPN":"この子はどれくらい持ち堪えられると思いますか？","ENG":"How long do you think she'll last?","TWN":"博士覺得這次的孩子能撐多久？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"그건 이제부터 지켜봐야겠지.","JPN":"それはこれからの様子を見るしかないだろう。","ENG":"We'll have to see about that.","TWN":"這個還有待觀察。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"곧 수술을 받게 될 아이와 함께 지내게 되겠는데요.","JPN":"もうすぐ手術を受ける子と一緒に過ごすことになりますね。","ENG":"She'll be sharing a room with another girl who will soon undergo surgery.","TWN":"我們把她安排在雙人房，和另一個即將進行手術的孩子一起住。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"……떠나기 전까진 아이들에게 최대한 잘 대해주게.","JPN":"……ここを出るまで、なるべく子どもたちにはよくしてやってくれ。","ENG":"Make sure to take good care of them until they are sent off.","TWN":"……在送走之前，儘量對孩子們好一點。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"그래야 메모리 코어를 제작할 때 편하니까.","JPN":"その方がメモリーコアを製作する時に楽だからな。","ENG":"It'll make creating the memory cores easier.","TWN":"這樣製作記憶核心時會更方便。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"알겠습니다.","JPN":"承知いたしました。","ENG":"Understood.","TWN":"好的。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"안녕?","JPN":"こんにちは。","ENG":"Hi.","TWN":"嗨？"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"만나서 반가워. 난 네 룸메이트야. 선배이기도 하지.","JPN":"はじめまして。私はあなたのルームメイトだよ。先輩になるね。","ENG":"It's so nice to meet you. I'm your roommate and also your senior.","TWN":"很高興見到你，我是你的室友，也是你的前輩。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"너무 긴장하지 마. 여긴 군사기관이라곤 해도, 딱히 군기 잡는 분위기는 아니거든.","JPN":"あまり緊張しないでね。ここは軍事機関だけど、そんなに堅苦しい雰囲気じゃないから。","ENG":"Don't be so nervous. Even if this place is a military facility, they aren't that strict around here.","TWN":"不要太緊張，雖然這裡是軍事機構，但並沒有特別嚴肅的氛圍。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"저, 전…! 오, 오늘 이곳에 입대한… <color=#ffd34c>마브카</color> 입니다!","JPN":"わ、私は……！　きょ、今日ここに入隊した……<color=#ffd34c>マブカ</color>です！","ENG":"I-I'm...! <color=#ffd34c>Mavka</color>... I just got enlisted today!","TWN":"我，我是……！今，今天剛入伍的……<color=#ffd34c>瑪卡</color>！"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"아하핫! 그렇게 긴장하지 말라니까~","JPN":"あははっ！　そんなに緊張しなくていいんだよ～","ENG":"Ah hah hah! Relax a little!","TWN":"啊哈哈哈哈！不要那麼緊張嘛～"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"귀여운 이름이네. 얼굴도 이쁘고.","JPN":"素敵な名前だね。お顔も可愛いし。","ENG":"That's a cute name. And you're so pretty.","TWN":"是很美的名字呢，臉也長得很漂亮。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"난 ■■■라고 해. 오늘부터 같이 지낼 사이인데, 잘해보자?","JPN":"私は■■■だよ。今日から一緒に暮らすんだから、仲よくしようね。","ENG":"I'm ■■■. We'll be living together from now on, so let's be friends.","TWN":"我叫■■■，從今天開始我們會一起生活，好好相處吧？"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"여긴 카운터를 양성하는 군사기관이지만, 사실상 학교야 학교.","JPN":"ここはカウンターを育成する軍事機関だけど、本当は学校なんだよ。","ENG":"Although this place is a military institution for training Counters, it's just an ordinary school.","TWN":"這裡雖然是培養制裁者的軍事機構，但實際上更像是學校。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"청춘을 즐긴다 생각하면서 느긋하게 있으면 돼.","JPN":"青春を楽しむと思ってゆっくりしていいから。","ENG":"Just think of it as having fun and enjoying life here.","TWN":"就當是在享受青春，放輕鬆點就好。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"그리고 존댓말 쓰지 말아줄래? 솔직히 불편하거든.","JPN":"それと、敬語はやめてくれる？　なんか落ち着かないから。","ENG":"Also, could you stop talking so rigidly to me? It's kinda uncomfortable.","TWN":"還有，說話不用那麼客氣，老實說，我覺得反而有點怪。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"으, 응… 알겠습니다.","JPN":"う、うん……わかりました。","ENG":"U-um... I'll try.","TWN":"嗯，嗯……知道了。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"아하하. 재밌는 아이네. 즐거운 나날이 될 것 같아.","JPN":"あはは。面白い子。毎日楽しくなりそうだね。","ENG":"Ah hah hah! You're funny. I think we're going to have fun together.","TWN":"嘻嘻，真是有趣的孩子。感覺我們在一起會很愉快。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"근데 있지. 선생님께서 난 이제 카운터가 될 거라고 해서, 오래는 못 볼 것 같아.","JPN":"でもね。先生が私はもうすぐカウンターになるって言うから、そう長く一緒にはいられないみたい。","ENG":"But hey. The teacher said that I'm going to become a Counter soon, so we won't be able to spend a lot of time together.","TWN":"不過老師說我馬上就要成為制裁者了，所以可能不會和你相處太久。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KIND_DOLL_NPC_NULL","text":{"KOREA":"너도 언젠간 이 곳에서 카운터가 될 테니까, 나중에 만나면 꼭 인사해 줘?","JPN":"あなたもいつかここでカウンターになるんだから、再会したら必ず挨拶してね。","ENG":"But you'll also become a Counter one day, so say hi to me when we meet later, okay?","TWN":"你也會在這裡成為制裁者的，以後見面一定要打招呼喔？"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"으, 응…! 절대 잊지 않을게… 요!","JPN":"う、うん……！　絶対忘れない……です！","ENG":"O-okay...! I'll never forget... you!","TWN":"嗯，嗯……！絕對不會忘記……的！"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"KIND_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};